import scala.collection.mutable

def solve(c: Long, connections: Array[Array[Long]], queries: Array[Array[Long]]): Array[Long] = {
  val parent = Array.ofDim[Int](c.toInt + 1)
  val rank = Array.ofDim[Int](c.toInt + 1)
  for (i <- 1 to c.toInt) {
    parent(i) = i
    rank(i) = 1
  }

  def find(x: Int): Int = {
    var root = x
    while (parent(root) != root) {
      root = parent(root)
    }
    var current = x
    while (parent(current) != root) {
      val next = parent(current)
      parent(current) = root
      current = next
    }
    root
  }

  def union(x: Int, y: Int): Unit = {
    val rootX = find(x)
    val rootY = find(y)
    if (rootX != rootY) {
      if (rank(rootX) < rank(rootY)) {
        parent(rootX) = rootY
      } else {
        parent(rootY) = rootX
        if (rank(rootX) == rank(rootY)) {
          rank(rootX) += 1
        }
      }
    }
  }

  for (conn <- connections) {
    val u = conn(0).toInt
    val v = conn(1).toInt
    union(u, v)
  }

  val rootToStations = mutable.HashMap[Int, List[Int]]()
  for (i <- 1 to c.toInt) {
    val root = find(i)
    if (!rootToStations.contains(root)) {
      rootToStations(root) = List(i)
    } else {
      rootToStations(root) += i
    }
  }

  val rootToSet = mutable.HashMap[Int, mutable.SortedSet[Int]]()
  for (root <- rootToStations.keys) {
    val stations = rootToStations(root)
    val sortedSet = stations.sorted
    rootToSet(root) = mutable.SortedSet.from(sortedSet)
  }

  val online = Array.ofDim[Boolean](c.toInt + 1)
  for (i <- 1 to c.toInt) {
    online(i) = true
  }

  val result = Array.ofDim[Long](queries.length)
  var idx = 0
  for (query <- queries) {
    val typeQ = query(0).toInt
    val x = query(1).toInt
    if (typeQ == 1) {
      if (online(x)) {
        result(idx) = x.toLong
      } else {
        val root = find(x)
        val s = rootToSet(root)
        if (s.isEmpty) {
          result(idx) = -1.toLong
        } else {
          result(idx) = s.min.toLong
        }
      }
      idx += 1
    } else {
      online(x) = false
      val root = find(x)
      rootToSet(root) -= x
    }
  }
  result
}
