def solve(c: Long, connections: Array[Array[Long]], queries: Array[Array[Long]]): Array[Long] = {
  val n = c.toInt
  val componentId = Array.fill(n + 1)(-1)
  val adj = mutable.HashMap[Long, List[Long]]()

  for (connection <- connections) {
    val u = connection(0)
    val v = connection(1)
    adj.put(u, u :: adj.getOrElse(u, Nil) :+ v)
    adj.put(v, v :: adj.getOrElse(v, Nil) :+ u)
  }

  val componentStations = mutable.HashMap[Int, List[Long]]()
  var currentId = 0

  for (station <- 1 to n) {
    if (componentId(station) == -1) {
      val queue = mutable.Queue[Long](station)
      componentId(station) = currentId
      val component = mutable.ListBuffer[Long]()
      component += station
      while (queue.nonEmpty) {
        val node = queue.dequeue()
        for (neighbor <- adj.getOrElse(node, Nil)) {
          if (componentId(neighbor) == -1) {
            componentId(neighbor) = currentId
            component += neighbor
            queue.enqueue(neighbor)
          }
        }
      }
      componentStations(currentId) = component.toList
      currentId += 1
    }
  }

  val componentSets = mutable.HashMap[Int, mutable.TreeSet[Long]]()
  for (i <- 0 until currentId) {
    val stations = componentStations(i)
    componentSets(i) = mutable.TreeSet(stations: _*)
  }

  val result = mutable.ArrayBuffer[Long]()

  for (query <- queries) {
    val typeQ = query(0)
    val x = query(1)
    val xInt = x.toInt
    if (typeQ == 1) {
      val compId = componentId(xInt)
      val compSet = componentSets(compId)
      if (compSet.contains(xInt)) {
