class DSU(val size: Int) {
  val parent: Array[Int] = Array.ofDim(size + 1)
  val rank: Array[Int] = Array.ofDim(size + 1)
  for (i <- 1 to size) {
    parent(i) = i
    rank(i) = 0
  }
  def find(x: Int): Int = {
    if (parent(x) != x) parent(x) = find(parent(x))
    parent(x)
  }
  def union(x: Int, y: Int): Unit = {
    val fx = find(x)
    val fy = find(y)
    if (fx != fy) {
      if (rank(fx) > rank(fy)) parent(fy) = fx
      else if (rank(fx) < rank(fy)) parent(fx) = fy
      else {
        parent(fy) = fx
        rank(fx) += 1
      }
    }
  }
}

def solve(c: Long, connections: Array[Array[Long]], queries: Array[Array[Long]]): Array[Long] = {
  val size = c.toInt
  val dsu = new DSU(size)
  for (conn <- connections) {
    val u = conn(0).toInt
    val v = conn(1).toInt
    dsu.union(u, v)
  }

  val rootToStations = scala.collection.mutable.HashMap[Int, scala.collection.mutable.PriorityQueue[Int]]()
  for (i <- 1 to size) {
    val root = dsu.find(i)
    if (!rootToStations.contains(root)) {
      rootToStations(root) = scala.collection.mutable.PriorityQueue[Int]()
    }
    rootToStations(root) += i
  }

  val online = Array.fill(size + 1)(true)
  val result = scala.collection.mutable.ArrayBuffer[Long]()

  for (query <- queries) {
    val typeQ = query(0).toInt
    val x = query(1).toInt
    if (typeQ == 1) {
      if (online(x)) {
        result += x.toLong
      } else {
        val root = dsu.find(x)
        val heap = rootToStations(root)
        while (heap.nonEmpty && !online(heap.head)) {
          heap.dequeue()
        }
        if (heap.isEmpty) {
          result += -1.toLong
        } else {
          result += heap.head.toLong
        }
      }
    } else {
      online(x) = false
    }
  }

  result.toArray
}
